1106 class InstructionsState {
1107   /// MainOp and AltOp are primarily determined by getSameOpcode. Currently,
1108   /// only BinaryOperator, CastInst, and CmpInst support alternate instructions
1109   /// (i.e., AltOp is not equal to MainOp; this can be checked using
1110   /// isAltShuffle).
1111   /// A rare exception is TrySplitNode, where the InstructionsState is derived
1112   /// from getMainAltOpsNoStateVL.
1113   /// For those InstructionsState that use alternate instructions, the resulting
1114   /// vectorized output ultimately comes from a shufflevector. For example,
1115   /// given a vector list (VL):
1116   /// VL[0] = add i32 a, e
1117   /// VL[1] = sub i32 b, f
1118   /// VL[2] = add i32 c, g
1119   /// VL[3] = sub i32 d, h
1120   /// The vectorized result would be:
1121   /// intermediated_0 = add <4 x i32> <a, b, c, d>, <e, f, g, h>
1122   /// intermediated_1 = sub <4 x i32> <a, b, c, d>, <e, f, g, h>
1123   /// result = shufflevector <4 x i32> intermediated_0,
1124   ///                        <4 x i32> intermediated_1,
1125   ///                        <4 x i32> <i32 0, i32 5, i32 2, i32 7>
1126   /// Since shufflevector is used in the final result, when calculating the cost
1127   /// (getEntryCost), we must account for the usage of shufflevector in
1128   /// GetVectorCost.
1129   Instruction *MainOp = nullptr;
1130   Instruction *AltOp = nullptr;
1131 
1132 public:
1133   Instruction *getMainOp() const {
1134     assert(valid() && "InstructionsState is invalid.");
1135     return MainOp;
1136   }
1137 
1138   Instruction *getAltOp() const {
1139     assert(valid() && "InstructionsState is invalid.");
1140     return AltOp;
1141   }
1142 
1143   /// The main/alternate opcodes for the list of instructions.
1144   unsigned getOpcode() const { return getMainOp()->getOpcode(); }
1145 
1146   unsigned getAltOpcode() const { return getAltOp()->getOpcode(); }
1147 
1148   /// Some of the instructions in the list have alternate opcodes.
1149   bool isAltShuffle() const { return getMainOp() != getAltOp(); }
1150 
1151   /// Checks if the instruction matches either the main or alternate opcode.
1152   /// \returns
1153   /// - MainOp if \param I matches MainOp's opcode directly or can be converted
1154   /// to it
1155   /// - AltOp if \param I matches AltOp's opcode directly or can be converted to
1156   /// it
1157   /// - nullptr if \param I cannot be matched or converted to either opcode
1158   Instruction *getMatchingMainOpOrAltOp(Instruction *I) const {
1159     assert(MainOp && "MainOp cannot be nullptr.");
1160     if (I->getOpcode() == MainOp->getOpcode())
1161       return MainOp;
1162     // Prefer AltOp instead of interchangeable instruction of MainOp.
1163     assert(AltOp && "AltOp cannot be nullptr.");
1164     if (I->getOpcode() == AltOp->getOpcode())
1165       return AltOp;
1166     if (!I->isBinaryOp())
1167       return nullptr;
1168     BinOpSameOpcodeHelper Converter(MainOp);
1169     if (Converter.add(I) && Converter.add(MainOp) && !Converter.hasAltOp())
1170       return MainOp;
1171     return AltOp;
1172   }
1173 
1174   /// Checks if main/alt instructions are shift operations.
1175   bool isShiftOp() const {
1176     return getMainOp()->isShift() && getAltOp()->isShift();
1177   }
1178 
1179   /// Checks if main/alt instructions are bitwise logic operations.
1180   bool isBitwiseLogicOp() const {
1181     return getMainOp()->isBitwiseLogicOp() && getAltOp()->isBitwiseLogicOp();
1182   }
1183 
1184   /// Checks if main/alt instructions are mul/div/rem/fmul/fdiv/frem operations.
1185   bool isMulDivLikeOp() const {
1186     constexpr std::array<unsigned, 8> MulDiv = {
1187         Instruction::Mul,  Instruction::FMul, Instruction::SDiv,
1188         Instruction::UDiv, Instruction::FDiv, Instruction::SRem,
1189         Instruction::URem, Instruction::FRem};
1190     return is_contained(MulDiv, getOpcode()) &&
1191            is_contained(MulDiv, getAltOpcode());
1192   }
1193 
1194   /// Checks if main/alt instructions are add/sub/fadd/fsub operations.
1195   bool isAddSubLikeOp() const {
1196     constexpr std::array<unsigned, 4> AddSub = {
1197         Instruction::Add, Instruction::Sub, Instruction::FAdd,
1198         Instruction::FSub};
1199     return is_contained(AddSub, getOpcode()) &&
1200            is_contained(AddSub, getAltOpcode());
1201   }
1202 
1203   /// Checks if main/alt instructions are cmp operations.
1204   bool isCmpOp() const {
1205     return (getOpcode() == Instruction::ICmp ||
1206             getOpcode() == Instruction::FCmp) &&
1207            getAltOpcode() == getOpcode();
1208   }
1209 
1210   /// Checks if the current state is valid, i.e. has non-null MainOp
1211   bool valid() const { return MainOp && AltOp; }
1212 
1213   explicit operator bool() const { return valid(); }
1214 
1215   InstructionsState() = delete;
1216   InstructionsState(Instruction *MainOp, Instruction *AltOp)
1217       : MainOp(MainOp), AltOp(AltOp) {}
1218   static InstructionsState invalid() { return {nullptr, nullptr}; }
1219 };
