1221 std::pair<Instruction *, SmallVector<Value *>>
1222 convertTo(Instruction *I, const InstructionsState &S) {
1223   Instruction *SelectedOp = S.getMatchingMainOpOrAltOp(I);
1224   assert(SelectedOp && "Cannot convert the instruction.");
1225   if (I->isBinaryOp()) {
1226     BinOpSameOpcodeHelper Converter(I);
1227     return std::make_pair(SelectedOp, Converter.getOperand(SelectedOp));
1228   }
1229   return std::make_pair(SelectedOp, SmallVector<Value *>(I->operands()));
