1494 /// possible scalar operand in vectorized instruction.
1495 static bool doesInTreeUserNeedToExtract(Value *Scalar, Instruction *UserInst,
1496                                         TargetLibraryInfo *TLI,
1497                                         const TargetTransformInfo *TTI) {
1498   if (!UserInst)
