1501   switch (Opcode) {
1502   case Instruction::Load: {
1503     LoadInst *LI = cast<LoadInst>(UserInst);
1504     return (LI->getPointerOperand() == Scalar);
1505   }
1506   case Instruction::Store: {
1507     StoreInst *SI = cast<StoreInst>(UserInst);
1508     return (SI->getPointerOperand() == Scalar);
1509   }
1510   case Instruction::Call: {
1511     CallInst *CI = cast<CallInst>(UserInst);
1512     Intrinsic::ID ID = getVectorIntrinsicIDForCall(CI, TLI);
1513     return any_of(enumerate(CI->args()), [&](auto &&Arg) {
1514       return isVectorIntrinsicWithScalarOpAtArg(ID, Arg.index(), TTI) &&
1515              Arg.value().get() == Scalar;
1516     });
1517   }
1518   default:
1519     return false;
1520   }
