1096   bool hasAltOp() const { return AltOp.I; }
1097   unsigned getAltOpcode() const {
1098     return hasAltOp() ? AltOp.getOpcode() : getMainOpcode();
1099   }
1100   SmallVector<Value *> getOperand(const Instruction *I) const {
1101     return MainOp.getOperand(I);
