2729     /// Helper for reorderOperandVecs.
2730     /// \returns the lane that we should start reordering from. This is the one
2731     /// which has the least number of operands that can freely move about or
2732     /// less profitable because it already has the most optimal set of operands.
2733     unsigned getBestLaneToStartReordering() const {
2734       unsigned Min = UINT_MAX;
2735       unsigned SameOpNumber = 0;
2736       // std::pair<unsigned, unsigned> is used to implement a simple voting
2737       // algorithm and choose the lane with the least number of operands that
2738       // can freely move about or less profitable because it already has the
2739       // most optimal set of operands. The first unsigned is a counter for
2740       // voting, the second unsigned is the counter of lanes with instructions
2741       // with same/alternate opcodes and same parent basic block.
2742       MapVector<unsigned, std::pair<unsigned, unsigned>> HashMap;
2743       // Try to be closer to the original results, if we have multiple lanes
2744       // with same cost. If 2 lanes have the same cost, use the one with the
2745       // highest index.
2746       for (int I = getNumLanes(); I > 0; --I) {
2747         unsigned Lane = I - 1;
2748         OperandsOrderData NumFreeOpsHash =
2749             getMaxNumOperandsThatCanBeReordered(Lane);
2750         // Compare the number of operands that can move and choose the one with
2751         // the least number.
2752         if (NumFreeOpsHash.NumOfAPOs < Min) {
2753           Min = NumFreeOpsHash.NumOfAPOs;
2754           SameOpNumber = NumFreeOpsHash.NumOpsWithSameOpcodeParent;
2755           HashMap.clear();
2756           HashMap[NumFreeOpsHash.Hash] = std::make_pair(1, Lane);
2757         } else if (NumFreeOpsHash.NumOfAPOs == Min &&
2758                    NumFreeOpsHash.NumOpsWithSameOpcodeParent < SameOpNumber) {
2759           // Select the most optimal lane in terms of number of operands that
2760           // should be moved around.
2761           SameOpNumber = NumFreeOpsHash.NumOpsWithSameOpcodeParent;
2762           HashMap[NumFreeOpsHash.Hash] = std::make_pair(1, Lane);
2763         } else if (NumFreeOpsHash.NumOfAPOs == Min &&
2764                    NumFreeOpsHash.NumOpsWithSameOpcodeParent == SameOpNumber) {
2765           auto [It, Inserted] =
2766               HashMap.try_emplace(NumFreeOpsHash.Hash, 1, Lane);
2767           if (!Inserted)
2768             ++It->second.first;
2769         }
2770       }
2771       // Select the lane with the minimum counter.
2772       unsigned BestLane = 0;
2773       unsigned CntMin = UINT_MAX;
2774       for (const auto &Data : reverse(HashMap)) {
2775         if (Data.second.first < CntMin) {
2776           CntMin = Data.second.first;
2777           BestLane = Data.second.second;
2778         }
2779       }
2780       return BestLane;
2781     }
